const express = require('express');
const OAuth2Server = require('oauth2-server');

const app = express();

const server = new OAuth2Server({
  clients: [], // Replace with actual client information
  accessTokenLifetime: 3600,
});

app.use(express.json());

app.post('/oauth/token', server.token(), (req, res) => {
  res.json(req.oauthToken);
});

app.use((req, res, next) => {
  if (req.headers.authorization) {
    const bearerToken = req.headers.authorization.replace(/^Bearer /, '');
    server.verifyAccessToken(bearerToken, (err, token) => {
      if (err) {
        return res.status(401).json({ error: 'Unauthorized' });
      }
      req.oauthToken = token;
      next();
    });
  } else {
    return res.status(401).json({ error: 'Unauthorized' });
  }
});

app.listen(3000, () => {
  console.log('OAuth 2.0 resource server running on port 3000');
});